parameters.jsonBody:
={
  "query": "query booking($id: Int) { booking(id: $id) { id uuid done dealership_uuid branch_uuid dealership { name } branch { name } booking_begin booking_end genre note customer { aggregate_id first_name last_name email phone_number } car { title license_plate } pickup_service_area { name } retrun_service_area { name } duration { days hours total_days } pricing { pickup_price return_price ot_price grace_price discount pricing_rate { date note price } grand_total } tax_invoice { full_name tax_id branch_number address postcode email } } }",
  "variables": {
    "id": {{ $('extract booking id').item.json.booking_id }}
  }
}

={
  "to": "{{ $('get dealer group id').item.json.line_group_chat_id }}",
  "messages": [
    {
      "type": "flex",
      "altText": "{{ '🚗 การจองใหม่ #' + $('get booking detail').item.json.data.booking.id }}",
      "contents": {
        "type": "bubble",
        "header": {
          "type": "box",
          "layout": "vertical",
          "backgroundColor": "#1B6AE3",
          "paddingAll": "16px",
          "contents": [
            {
              "type": "box",
              "layout": "horizontal",
              "contents": [
                { "type": "text", "text": "🚗 การจองใหม่!", "weight": "bold", "color": "#FFFFFF", "size": "md", "flex": 3 },
                { "type": "text", "text": "{{ '#' + $('get booking detail').item.json.data.booking.id }}", "weight": "bold", "color": "#FFFFFF", "size": "md", "align": "end", "flex": 2 }
              ]
            },
            {
              "type": "text",
              "text": "{{ ({'daily':'เช่ารถขับเอง','transfer':'มีคนขับ'})[$('get booking detail').item.json.data.booking.genre] || $('get booking detail').item.json.data.booking.genre }}",
              "color": "#C5D8FF",
              "size": "sm",
              "margin": "xs"
            }
          ]
        },
        "body": {
          "type": "box",
          "layout": "vertical",
          "spacing": "md",
          "paddingAll": "16px",
          "contents": [
            {
              "type": "box",
              "layout": "vertical",
              "spacing": "sm",
              "contents": [
                {
                  "type": "box",
                  "layout": "horizontal",
                  "contents": [
                    { "type": "text", "text": "📅 รับรถ", "color": "#888888", "size": "sm", "flex": 2 },
                    { "type": "text", "text": "{{ new Date($('get booking detail').item.json.data.booking.booking_begin*1000).toLocaleString('th-TH',{timeZone:'Asia/Bangkok',calendar:'gregory',day:'numeric',month:'long',year:'numeric',hour:'2-digit',minute:'2-digit'}).replace(',','')+'น.' }}", "size": "sm", "flex": 5, "wrap": true, "weight": "bold" }
                  ]
                },
                {
                  "type": "box",
                  "layout": "horizontal",
                  "contents": [
                    { "type": "text", "text": "🏁 คืนรถ", "color": "#888888", "size": "sm", "flex": 2 },
                    { "type": "text", "text": "{{ new Date($('get booking detail').item.json.data.booking.booking_end*1000).toLocaleString('th-TH',{timeZone:'Asia/Bangkok',calendar:'gregory',day:'numeric',month:'long',year:'numeric',hour:'2-digit',minute:'2-digit'}).replace(',','')+'น.' }}", "size": "sm", "flex": 5, "wrap": true, "weight": "bold" }
                  ]
                },
                { "type": "text", "text": "{{ (()=>{ const d=$('get booking detail').item.json.data.booking.duration; const p=[]; if(d.days>0)p.push(d.days+' วัน'); if(d.hours>0)p.push(d.hours+' ชั่วโมง'); return 'รวม '+p.join(' '); })() }}", "color": "#888888", "size": "xs" }
              ]
            },
            { "type": "separator" },
            {
              "type": "box",
              "layout": "horizontal",
              "contents": [
                { "type": "text", "text": "📍 สถานที่", "color": "#888888", "size": "sm", "flex": 2 },
                { "type": "text", "text": "{{ $('get booking detail').item.json.data.booking.pickup_service_area.name }}", "size": "sm", "flex": 5, "wrap": true, "weight": "bold" }
              ]
            },
            { "type": "separator" },
            {
              "type": "box",
              "layout": "horizontal",
              "contents": [
                { "type": "text", "text": "🚘 รถ", "color": "#888888", "size": "sm", "flex": 2 },
                { "type": "text", "text": "{{ $('get booking detail').item.json.data.booking.car.title + ($('get booking detail').item.json.data.booking.car.license_plate ? '\\nทะเบียน: '+$('get booking detail').item.json.data.booking.car.license_plate : '') }}", "size": "sm", "flex": 5, "wrap": true }
              ]
            },
            { "type": "separator" },
            {
              "type": "box",
              "layout": "vertical",
              "spacing": "xs",
              "contents": [
                {
                  "type": "box",
                  "layout": "horizontal",
                  "contents": [
                    { "type": "text", "text": "👤", "size": "sm", "flex": 1 },
                    { "type": "text", "text": "{{ $('get booking detail').item.json.data.booking.customer.first_name+' '+$('get booking detail').item.json.data.booking.customer.last_name }}", "size": "sm", "flex": 6, "wrap": true, "weight": "bold" }
                  ]
                },
                {
                  "type": "box",
                  "layout": "horizontal",
                  "contents": [
                    { "type": "text", "text": "📞", "size": "sm", "flex": 1 },
                    { "type": "text", "text": "{{ $('get booking detail').item.json.data.booking.customer.phone_number }}", "size": "sm", "flex": 6 }
                  ]
                },
                {
                  "type": "box",
                  "layout": "horizontal",
                  "contents": [
                    { "type": "text", "text": "✉️", "size": "sm", "flex": 1 },
                    { "type": "text", "text": "{{ $('get booking detail').item.json.data.booking.customer.email }}", "size": "sm", "flex": 6, "wrap": true }
                  ]
                }
              ]
            },
            { "type": "separator" },
            {
              "type": "box",
              "layout": "horizontal",
              "contents": [
                { "type": "text", "text": "หมายเหตุ", "color": "#888888", "size": "sm", "flex": 2, "wrap": true },
                { "type": "text", "text": "{{ $('get booking detail').item.json.data.booking.note || '-' }}", "size": "sm", "flex": 5, "wrap": true, "color": "#1B6AE3", "maxLines": 3 }
              ]
            },
            { "type": "separator" },
            {
              "type": "box",
              "layout": "vertical",
              "spacing": "xs",
              "contents": [
                { "type": "text", "text": "💳 ราคาหน้าเว็บไซต์", "weight": "bold", "size": "sm", "color": "#333333" },
                {
                  "type": "box",
                  "layout": "horizontal",
                  "margin": "xs",
                  "contents": [
                    {
                      "type": "text",
                      "text": "{{ (()=>{ const p=$('get booking detail').item.json.data.booking.pricing; return p.pricing_rate.map(r=>{ const d=new Date(r.date*1000).toLocaleDateString('th-TH',{timeZone:'Asia/Bangkok',calendar:'gregory',day:'2-digit',month:'2-digit',year:'numeric'}); const note=r.note.trim(); const t=note.length>10?note.substring(0,15)+'...':note; return d+' ('+t+')'; }).join('\\n'); })() }}",
                      "size": "xs", "color": "#555555", "wrap": true, "flex": 6
                    },
                    {
                      "type": "text",
                      "text": "{{ (()=>{ const p=$('get booking detail').item.json.data.booking.pricing; return p.pricing_rate.map(r=>'฿'+(r.price/100).toLocaleString('en-US')).join('\\n'); })() }}",
                      "size": "xs", "color": "#555555", "wrap": true, "flex": 2, "align": "end"
                    }
                  ]
                },
                {
                  "type": "box",
                  "layout": "horizontal",
                  "contents": [
                    { "type": "text", "text": "ค่าล่วงเวลา", "color": "#888888", "size": "xs", "flex": 4 },
                    { "type": "text", "text": "{{ '฿'+($('get booking detail').item.json.data.booking.pricing.grace_price/100).toLocaleString('en-US') }}", "size": "xs", "flex": 3, "align": "end" }
                  ]
                },
                {
                  "type": "box",
                  "layout": "horizontal",
                  "contents": [
                    { "type": "text", "text": "ค่าบริการนอกเวลาทำการ", "color": "#888888", "size": "xs", "flex": 4 },
                    { "type": "text", "text": "{{ '฿'+($('get booking detail').item.json.data.booking.pricing.ot_price/100).toLocaleString('en-US') }}", "size": "xs", "flex": 3, "align": "end" }
                  ]
                },
                {
                  "type": "box",
                  "layout": "horizontal",
                  "contents": [
                    { "type": "text", "text": "ค่าบริการส่งรถ", "color": "#888888", "size": "xs", "flex": 4 },
                    { "type": "text", "text": "{{ '฿'+($('get booking detail').item.json.data.booking.pricing.pickup_price/100).toLocaleString('en-US') }}", "size": "xs", "flex": 3, "align": "end" }
                  ]
                },
                {
                  "type": "box",
                  "layout": "horizontal",
                  "contents": [
                    { "type": "text", "text": "ค่าบริการรับรถ", "color": "#888888", "size": "xs", "flex": 4 },
                    { "type": "text", "text": "{{ '฿'+($('get booking detail').item.json.data.booking.pricing.return_price/100).toLocaleString('en-US') }}", "size": "xs", "flex": 3, "align": "end" }
                  ]
                },
                {
                  "type": "box",
                  "layout": "horizontal",
                  "contents": [
                    { "type": "text", "text": "ส่วนลด", "color": "#888888", "size": "xs", "flex": 4 },
                    { "type": "text", "text": "{{ $('get booking detail').item.json.data.booking.pricing.discount > 0 ? '-฿'+($('get booking detail').item.json.data.booking.pricing.discount/100).toLocaleString('en-US') : '-' }}", "size": "xs", "flex": 3, "align": "end", "color": "#CC3300" }
                  ]
                },
                {
                  "type": "box",
                  "layout": "horizontal",
                  "backgroundColor": "#EEF4FF",
                  "paddingAll": "8px",
                  "cornerRadius": "6px",
                  "margin": "sm",
                  "contents": [
                    { "type": "text", "text": "💰 รวมทั้งสิ้น", "weight": "bold", "size": "sm", "flex": 3 },
                    { "type": "text", "text": "{{ '฿'+($('get booking detail').item.json.data.booking.pricing.grand_total/100).toLocaleString('en-US') }}", "weight": "bold", "size": "sm", "color": "#1B6AE3", "flex": 3, "align": "end" }
                  ]
                }
              ]
            }
          ]
        },
        "footer": {
          "type": "box",
          "layout": "vertical",
          "paddingAll": "12px",
          "spacing": "sm",
          "contents": [
            {
              "type": "box",
              "layout": "vertical",
              "backgroundColor": "#1B6AE3",
              "cornerRadius": "8px",
              "paddingAll": "11px",
              "action": {
                "type": "uri",
                "label": "ติดต่อลูกค้า",
                "uri": "{{ 'tel:' + $('get booking detail').item.json.data.booking.customer.phone_number.replace(/[^0-9+]/g,'') }}"
              },
              "contents": [
                { "type": "text", "text": "ติดต่อลูกค้า", "color": "#FFFFFF", "size": "md", "align": "center" }
              ]
            },
            {
              "type": "box",
              "layout": "vertical",
              "backgroundColor": "#FFFFFF",
              "borderColor": "#1B6AE3",
              "borderWidth": "1px",
              "cornerRadius": "8px",
              "paddingAll": "10px",
              "action": {
                "type": "uri",
                "label": "ดูรายละเอียดการจอง",
                "uri": "{{ $('config').first().json.manage_url + '/staff/bookings/' + $('get booking detail').item.json.data.booking.id }}"
              },
              "contents": [
                { "type": "text", "text": "ดูรายละเอียดการจอง", "color": "#1B6AE3", "size": "md", "align": "center" }
              ]
            }
          ]
        }
      }
    }
  ]
}

={
  "channel": "{{ $('config').first().json.slack_error_channel }}",
  "attachments": [
    {
      "color": "#E53935",
      "blocks": [
        {
          "type": "section",
          "text": {
            "type": "mrkdwn",
            "text": ":warning: *Dealer Notify — Error*"
          }
        },
        {
          "type": "section",
          "fields": [
            { "type": "mrkdwn", "text": "*Node ที่ fail:*\n`{{ $json.error?.source_node ?? $prevNode.name }}`" },
            { "type": "mrkdwn", "text": "*Booking ID:*\n`{{ $('extract booking id').first().json.booking_id ?? 'N/A' }}`" },
            { "type": "mrkdwn", "text": "*Execution ID:*\n`{{ $execution.id }}`" },
            { "type": "mrkdwn", "text": "*เวลา:*\n{{ $now.setZone('Asia/Bangkok').toFormat('dd/MM/yyyy HH:mm') }}" },
            { "type": "mrkdwn", "text": "*Dealer:*\n{{ $('get booking detail').item?.json?.data?.booking?.dealership?.name ?? 'N/A' }}\n`{{ $('get booking detail').item?.json?.data?.booking?.dealership_uuid ?? 'N/A' }}`" },
            { "type": "mrkdwn", "text": "*Branch:*\n{{ $('get booking detail').item?.json?.data?.booking?.branch?.name ?? 'N/A' }}\n`{{ $('get booking detail').item?.json?.data?.booking?.branch_uuid ?? 'N/A' }}`" }
          ]
        },
        {
          "type": "section",
          "text": {
            "type": "mrkdwn",
            "text": ":x: *Error*\n```{{ JSON.stringify($json.error?.message ?? $json.error ?? '(no message)').slice(1,-1) }}```"
          }
        },
        {
          "type": "actions",
          "elements": [
            {
              "type": "button",
              "text": { "type": "plain_text", "text": "ดู Execution ใน n8n" },
              "url": "https://nonprd-n8n.drivehub.co/workflow/{{ $workflow.id }}/executions/{{ $execution.id }}",
              "style": "danger"
            },
            {
              "type": "button",
              "text": { "type": "plain_text", "text": "เปิด Manage" },
              "url": "https://manage.drivehub.co/admin/home"
            }
          ]
        }
      ]
    }
  ]
}

={
  "channel": "{{ $('config').first().json.slack_ops_channel }}",
  "text": "🟢 n8n กลับมาทำงานแล้ว — มี booking ค้าง {{ $json.item_count }} รายการ",
  "blocks": [
    {
      "type": "header",
      "text": { "type": "plain_text", "text": "🟢 n8n กลับมาทำงานแล้ว", "emoji": true }
    },
    {
      "type": "section",
      "text": { "type": "mrkdwn", "text": "🙏 ส่ง manual ทั้งหมด *ถึง #{{ $json.max_id }}* เป็นตัวสุดท้าย (+ กด *Done* ในหลังบ้านทุกตัวที่ส่ง)\n🤖 Booking ใหม่หลัง #{{ $json.max_id }} bot จะส่งเองตามปกติ" }
    }
  ]
}
